create table dirkspzm32.isi_scanner_cfg (
    sid                     varchar2(2 char) not null enable,
    firma_nr                number(6, 0) not null enable,
    scanner_name            varchar2(255 char) not null enable,
    scanner_visuname        varchar2(15 char),
    scanner_prae            varchar2(15 char),
    scanner_post            varchar2(15 char),
    scanner_typ             varchar2(15 char),
    com_name                varchar2(15 char),
    scanner_funk_name       varchar2(255 char),
    appli_modul             varchar2(30 char),
    appli_funktion          varchar2(30 char),
    barcode_typ             varchar2(10 char),
    barcode_bez             varchar2(10 char),
    computername            varchar2(30 char),
    ls_login_id             number(6, 0),
    res_id                  number(*, 0),
    akt_aufgabe             varchar2(30 char),
    hersteller              varchar2(30 char),
    modell                  varchar2(30 char),
    scanner_daten           varchar2(50 char),
    appli_service           varchar2(30 char),
    appli_ziel_typ          varchar2(15 char),
    appli_ziel              varchar2(40 char),
    scanner_start_read      varchar2(40 char),
    scanner_message_no_read varchar2(40 char),
    drucker                 varchar2(255 char),
    config_params           varchar2(1024 char),
    scanner_enabled         varchar2(1 char),
    send_scan_res_1         varchar2(100 char),
    send_scan_res_2         varchar2(100 char),
    rcv_cmd_ack             varchar2(100 char)
);

alter table dirkspzm32.isi_scanner_cfg
    add constraint pk_scanner_cfg
        primary key ( sid,
                      firma_nr,
                      scanner_name )
            using index enable;


